import sailpoint.object.Identity;
Identity identity = context.getObjectByName(Identity.class, identityName);
return identity;

import sailpoint.object.Identity;
String managerEmail = "Not Available";
Identity identity = context.getObjectByName(Identity.class, identityName);
if(identity != null){
Identity managerIdentity = identity.getManager();
if(managerIdentity != null && managerIdentity.getEmail() != null){
managerEmail = managerIdentity.getEmail();
}
}
return managerEmail;

        import sailpoint.api.IdentityService;
        import sailpoint.object.Application;
        import sailpoint.object.Link;
        import sailpoint.object.Identity;
        
        trace(logName, "Ascension-Subprocess-Rehire-Notifications start for identity: " + identityName);
        
        trace(logName, "Entering Step: "+wfcontext.getStep().getName());
        
        Identity identity=context.getObjectByName(Identity.class,identityName);  
        Application applicationName=context.getObjectByName(Application.class,"DB-Peoplesoft-HCM-Primary");
        String identityType;
        IdentityService idService = new IdentityService(context);
        List links = idService.getLinks(identity,applicationName);
        if(null!=links)
        {
        for(Link link:links){
        identityType= link.getAttribute("PER_ORG");
        if(null!=identityType && "EMP".equalsIgnoreCase(identityType))
        {
        identityType="EMP";
        }
        else if(null!=identityType && "CWR".equalsIgnoreCase(identityType))
        {
        identityType="CWR";
        }
        else{
        return null;
        }
        }
        }
        debug(logName, "identityType" + identityType);
        trace(logName, "Exiting Step: "+wfcontext.getStep().getName());
        return identityType;

if(wfcase.hasErrors()){
workflow.put("stepName" , wfcontext.getStep().getName());
return true;
} else{
return false;
}

trace(logName, "Entering Step: "+wfcontext.getStep().getName());
String templateName = null;
if(identityType.equals("EMP")){
templateName = "Ascension-EmailTemplate-Rehire-EMP-Notification";
} else if(identityType.equals("CWR")){
templateName = "Ascension-EmailTemplate-Rehire-CWR-Notification";
}
trace(logName, "Exiting Step: "+wfcontext.getStep().getName());
return templateName;

if(wfcase.hasErrors()){
workflow.put("stepName" , wfcontext.getStep().getName());
return true;
} else{
return false;
}

          import sailpoint.object.Custom;

          List ccMembersList = new ArrayList();
          Custom custom = context.getObjectByName(Custom.class,"Ascension-Custom-Rehire-Configuration");
          if(null!=custom){
          Map emailAttributes = custom.get("Email Attributes");
          if(null != emailAttributes){
          ccMembersList = emailAttributes.get("cc");
          }
          }
          return ccMembersList;

        import sailpoint.object.Custom;

          String fromAddress=null;
          Custom custom = context.getObjectByName(Custom.class,"Ascension-Custom-Rehire-Configuration");
          if(null!=custom){
          Map emailAttributes = custom.get("Email Attributes");
          if(null != emailAttributes){
          fromAddress = emailAttributes.get("from");
          }
          }
          return fromAddress;

        import sailpoint.object.Custom;

          List toAddress= new ArrayList();
          String dlEmailAddress = null;
          String ministryDlEmailAddress = null;
          
          Custom contractorCustom = context.getObjectByName(Custom.class,"Ascension-Custom-ContractorConfiguration");
          
          //Get the Ministry DL Email address from the Custom Object
          if(null != contractorCustom){
          Map distributionLists = contractorCustom.get("DistributionList");
          dlEmailAddress = distributionLists.get("IDM");
          if(identity != null){
          String domain = identity.getStringAttribute("domain");
          if(null != distributionLists && !Util.isEmpty(domain)){
          ministryDlEmailAddress = distributionLists.get(domain);
          }
          }
          }
          
          //If the Email Address is not null add them to the To Address List
          if(Util.isNotNullOrEmpty(dlEmailAddress)){
          toAddress.add(dlEmailAddress);
          }
          if(Util.isNotNullOrEmpty(hiringManager) && !Util.nullSafeCaseInsensitiveEq(hiringManager, "Not Available")){
          toAddress.add(hiringManager);
          }
          if(Util.isNotNullOrEmpty(ministryDlEmailAddress)){
          toAddress.add(ministryDlEmailAddress);
          }
          addMessage(wfcontext, "Notification is sent to" + toAddress.toString());
          String toAddressStr = Util.join(toAddress, ",");
          return toAddressStr;

String startDate = null;
if(identity != null){
startDate = findEffectiveDate(identity);
}
if(Util.isEmpty(startDate)){
startDate = "Not Available";
}
return startDate;

if(wfcase.hasErrors()){
workflow.put("stepName" , wfcontext.getStep().getName());
return true;
} else{
return false;
}

if(wfcase.hasErrors()){
throw new RuntimeException("ERROR: in step - " + workflow.get("stepName") + " : " + wfcase.getErrors());
}
